  "glossary": [
    {
      "term": "ACID",
      "definition": "Prinsip transaksi: atomicity, consistency, isolation, durability."
    },
    {
      "term": "Aggregation",
      "definition": "Perhitungan ringkas seperti COUNT, SUM, AVG, MIN, dan MAX."
    },
    {
      "term": "CTE",
      "definition": "Common Table Expression, query sementara bernama yang ditulis dengan WITH."
    },
    {
      "term": "Foreign Key",
      "definition": "Kolom yang menghubungkan data ke primary key tabel lain."
    },
    {
      "term": "Index",
      "definition": "Struktur bantu untuk mempercepat pencarian, filter, join, dan pengurutan."
    },
    {
      "term": "Join",
      "definition": "Operasi menggabungkan baris dari dua atau lebih tabel."
    },
    {
      "term": "Normalization",
      "definition": "Proses merapikan struktur tabel untuk mengurangi duplikasi dan anomali."
    },
    {
      "term": "Primary Key",
      "definition": "Identitas unik setiap baris dalam sebuah tabel."
    },
    {
      "term": "Query Plan",
      "definition": "Rencana eksekusi query yang dibuat DBMS."
    },
    {
      "term": "Window Function",
      "definition": "Fungsi analitik yang bekerja pada jendela baris tanpa mereduksi seluruh baris seperti GROUP BY."
    },
    {
      "term": "View",
      "definition": "Query tersimpan yang dapat diperlakukan seperti tabel logis."
    },
    {
      "term": "Materialized View",
      "definition": "Hasil query yang disimpan secara fisik dan perlu di-refresh sesuai kebutuhan."
    },
    {
      "term": "SQL Injection",
      "definition": "Serangan ketika input pengguna dimasukkan ke query secara tidak aman."
    },
    {
      "term": "Prepared Statement",
      "definition": "Teknik query berparameter untuk memisahkan sintaks SQL dari input pengguna."
    },
    {
      "term": "Star Schema",
      "definition": "Model data warehouse dengan fact table di tengah dan dimension table di sekelilingnya."
    },
    {
      "term": "Grain",
      "definition": "Unit makna satu baris pada output query atau tabel fact, misalnya satu baris per pesanan atau per produk per hari."
    },
    {
      "term": "Cardinality",
      "definition": "Hubungan jumlah baris antara dua tabel yang menentukan risiko duplikasi ketika JOIN."
    },
    {
      "term": "RPO",
      "definition": "Recovery Point Objective, yaitu batas kehilangan data yang masih dapat diterima ketika pemulihan dilakukan."
    },
    {
      "term": "RTO",
      "definition": "Recovery Time Objective, yaitu batas waktu pemulihan layanan yang masih dapat diterima."
    },
    {
      "term": "Data Lineage",
      "definition": "Jejak asal, transformasi, dan penggunaan data dari sumber sampai laporan."
    },
    {
      "term": "Data Mart",
      "definition": "Subset data warehouse untuk kebutuhan analitik bidang tertentu, misalnya penjualan atau stok."
    },
    {
      "term": "SCD",
      "definition": "Slowly Changing Dimension, teknik menyimpan perubahan atribut dimensi dalam warehouse."
    },
    {
      "term": "Selectivity",
      "definition": "Tingkat kemampuan filter atau index dalam memperkecil jumlah baris yang dibaca."
    },
    {
      "term": "Masking",
      "definition": "Teknik menyamarkan sebagian data sensitif pada tampilan atau laporan."
    },
    {
      "term": "Data profiling",
      "definition": "Proses memeriksa pola, kelengkapan, duplikasi, dan anomali data sebelum analisis."
    },
    {
      "term": "Data lineage",
      "definition": "Jejak asal, transformasi, dan penggunaan data dari sumber sampai laporan."
    },
    {
      "term": "Query review",
      "definition": "Pemeriksaan query untuk memastikan sintaks, logika, efisiensi, dan keterbacaan."
    },
    {
      "term": "Star schema",
      "definition": "Model data warehouse dengan tabel fakta di tengah dan tabel dimensi di sekelilingnya."
    },
    {
      "term": "Watermark",
      "definition": "Penanda waktu atau ID terakhir yang dipakai untuk incremental load."
    },
    {
      "term": "SLA",
      "definition": "Service level agreement, ukuran layanan seperti waktu kirim atau waktu respons."
    },
    {
      "term": "RFM",
      "definition": "Recency, Frequency, Monetary; metode segmentasi pelanggan berdasarkan perilaku transaksi."
    },
    {
      "term": "Cohort",
      "definition": "Kelompok pengguna yang memiliki karakteristik atau periode awal aktivitas yang sama."
    },
    {
      "term": "Observability data",
      "definition": "Kemampuan memantau kesehatan data melalui metrik kualitas, volume, freshness, dan anomali."
    },
    {
      "term": "Expected output",
      "definition": "Hasil yang diharapkan dari query untuk membandingkan apakah logika query sudah benar."
    }
  ],
